import { useFormik } from "formik";
import { LeagueTable } from "../../objects/league-table";
import { PostLeagueTableResult } from "../../services/league-table-service";
import { useEffect, useState } from "react";
import { GetTeams } from "../../services/teams-service";
import { Team } from "../../objects/team"

const AdminResult = ()  =>
{
    const [teams, setTeams] = useState<Team []>();
    
    useEffect(() => {
        GetTeams().then((data) => setTeams(data));        
    },[])

    const formik = useFormik({
        initialValues :{ team: 0, season: 6, won : 0, lost: 0,drawn : 0, glsFor : 0,glsA : 0 },
        onSubmit : values => {
            const leageTable : LeagueTable = {id : 1, achieveablePoints: 0, gd : 0, pld : 0, points : 0, teamName : "",drawn : values.drawn,
                glsA : values.glsA, glsFor: values.glsFor,lost : values.lost, seasonId : values.season, teamId : values.team, won : values.won
            }
            PostLeagueTableResult(leageTable).then(formik.resetForm);
        }
    });

    return(

        <>       
        <div>           
            <form onSubmit={formik.handleSubmit}>
                <div className="row">
                    <div className="col-2">
                        <label htmlFor="team">Team</label>
                        <select id="team" {...formik.getFieldProps("team")}> 
                            <option value="">Select a team</option>
                            {teams?.map(option => (
                                <option key={option.id} value={option.id}>{option.name}</option>
                            ))}
                        </select>
                    </div>
                    <div className="col-2">
                        Season Id<input type="text" {...formik.getFieldProps("season")}/> 
                    </div>   
                    <div className="col-2">
                        Won<input type="text" {...formik.getFieldProps("won")}/> 
                    </div>
                    <div className="col-2">
                        Lost<input type="text" {...formik.getFieldProps("lost")}/> 
                    </div>   
                 </div>
                 <div className="row">
                   
                 </div>



                 
                 Won<input type="text" {...formik.getFieldProps("won")}/> 
                 Lost<input type="text" {...formik.getFieldProps("lost")}/> 
                 Drawn<input type="text" {...formik.getFieldProps("drawn")}/> 
                 Gls For<input type="text" {...formik.getFieldProps("glsFor")}/> 
                 Gls A<input type="text" {...formik.getFieldProps("glsA")}/> 
                 <button className="btn btn-primary" type="submit">Go</button>  
            </form>            
        </div>
        </>
    );
}

export default AdminResult;
